import { safeJsonForScript } from "./safeHtml.js";
import { themeCss } from "./theme.js";
export function htmlTemplate(vm, body) {
    const data = {
        events: vm.rawEvents,
        timeline: vm.timeline,
        graph: vm.graph.nodes,
        provider: vm.provider,
    };
    return `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Villani Flight Recorder</title><style>${themeCss()}</style></head><body>${body}<script>const replayData=${safeJsonForScript(data)};${clientJs()}</script></body></html>`;
}
function clientJs() {
    return `let selected=0;let selectedKind='event';let activeTab='Event Detail';const events=replayData.events||[];const graph=replayData.graph||[];function escHtml(s){return String(s??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]})}function limit(v){const s=String(v??'');return s.length>20000?s.slice(0,20000)+'\\n\\nOutput truncated to 20,000 characters. Full content was larger.':s}function template(id){return document.getElementById(id).innerHTML}function statusOf(ev){return ev.type==='error'||(ev.exitCode??0)!==0?'failed':((ev.warnings||[]).length||ev.type==='unknown')?'warning':'completed'}function eventHtml(ev){return '<div class="detail-hero"><div class="detail-icon"><svg viewBox="0 0 24 24"><path d="M7 3h7l4 4v14H7z"/><path d="M9 13h6M9 17h4"/></svg></div><div><h3>'+escHtml(ev.title||'Replay event')+'</h3><span class="status-chip">'+escHtml(statusOf(ev))+'</span><p>'+escHtml(ev.summary||ev.command||ev.path||'No summary captured')+'</p></div><div class="meta-grid"><b>Event ID</b><span>'+escHtml(ev.id||'Unavailable')+'</span><b>Started</b><span>'+escHtml(ev.timestamp||'Not captured')+'</span><b>Provider/Runner</b><span>'+escHtml(ev.provider||replayData.provider||'Unknown')+'</span><b>Duration</b><span>'+escHtml(ev.durationMs==null?'Not captured':ev.durationMs+'ms')+'</span><b>Path</b><span>'+escHtml(ev.path||'Unavailable')+'</span><b>Command</b><span>'+escHtml(ev.command||'Unavailable')+'</span><b>Exit code</b><span>'+escHtml(ev.exitCode??'Unavailable')+'</span></div></div>'+(ev.stdout||ev.stderr?'<p><button class="console-btn">View Logs</button></p>':'')}function graphHtml(n){return '<div class="detail-hero"><div class="detail-icon"><svg viewBox="0 0 24 24"><path d="M12 3l8 4v5c0 5-3.4 8-8 9-4.6-1-8-4-8-9V7z"/></svg></div><div><h3>'+escHtml(n.title||'Graph phase')+'</h3><span class="status-chip">'+escHtml(n.status||'phase')+'</span><p>'+escHtml(n.subtitle||'Replay phase detail')+'</p></div><div class="meta-grid"><b>Phase ID</b><span>'+escHtml(n.id||'Unavailable')+'</span><b>Provider/Runner</b><span>'+escHtml(replayData.provider||'Unknown')+'</span><b>Duration</b><span>'+escHtml(n.durationLabel||'Not captured')+'</span></div></div>'}function renderDetail(){const ev=events[selected]||events[0]||{};const node=graph[selected]||graph[0]||{};let html='';if(activeTab==='Event Detail')html=selectedKind==='graph'?graphHtml(node):eventHtml(ev);if(activeTab==='Changed Files')html='<pre>'+template('changedFiles')+'</pre>';if(activeTab==='Diff')html='<pre>'+template('gitDiff')+'</pre>';if(activeTab==='Raw JSON')html='<pre>'+escHtml(limit(JSON.stringify(selectedKind==='graph'?node:ev,null,2)))+'</pre>';if(activeTab==='Warnings')html='<pre>'+template('warningsData')+'</pre>';if(activeTab==='Redaction')html='<pre>'+template('redactionData')+'</pre>';document.getElementById('detailContent').innerHTML=html;const fill=document.getElementById('scrubFill');if(fill){const total=Math.max((events.length||1)-1,1);fill.style.width=Math.round((Math.min(selected,total)/total)*100)+'%'}}function setActiveTab(tab){activeTab=tab;document.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active',t.dataset.tab===activeTab))}document.querySelectorAll('[data-event-index]').forEach(btn=>btn.addEventListener('click',()=>{selected=Number(btn.dataset.eventIndex);selectedKind='event';setActiveTab('Event Detail');document.querySelectorAll('.timeline-row').forEach(r=>r.classList.toggle('selected',r===btn));renderDetail()}));document.querySelectorAll('[data-graph-index]').forEach(btn=>btn.addEventListener('click',()=>{selected=Number(btn.dataset.graphIndex);selectedKind='graph';setActiveTab('Event Detail');document.querySelectorAll('.graph-node').forEach(r=>r.classList.toggle('selected',r===btn));renderDetail()}));document.querySelectorAll('.tab').forEach(btn=>btn.addEventListener('click',()=>{setActiveTab(btn.dataset.tab);renderDetail()}));document.querySelectorAll('[data-filter]').forEach(btn=>btn.addEventListener('click',()=>{const f=btn.dataset.filter;document.querySelectorAll('[data-event-index]').forEach(row=>{const issue=row.classList.contains('warning')||row.classList.contains('failed');row.style.display=f==='all'||(f==='warnings'&&issue)?'grid':'none'})}));renderDetail();`;
}
